13	type Item = { type: string };
14	type Step = { op: "quote"; items: Item[] };
15	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
16	
17	const BLOCK_SIZE = 3;
18	const BLOCK_PREMIUM = 60;
19	
20	const isBlockOfSameType = (items: Item[]): boolean =>
21	  items.length === BLOCK_SIZE && items.every((i) => i.type === items[0].type);
22	
23	const sumOfBasePremiums = (items: Item[]): number =>
24	  items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
25	
26	const basePremiumFor = (items: Item[]): number =>
27	  isBlockOfSameType(items) ? BLOCK_PREMIUM : sumOfBasePremiums(items);
28	
29	const premiumFor = (items: Item[]): number => {
30	  const basePremium = basePremiumFor(items);
31	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
32	  return Math.ceil(basePremium + firstInsuranceSurcharge + PROCESSING_FEE);
33	};
34	
35	type QuoteResult = { premium: number };
36	type ScenarioOutput = { results: QuoteResult[] };
37	
38	const quoteStep = ({ items }: Step): QuoteResult => ({
39	  premium: premiumFor(items),
40	});
41	
42	export const runScenario = (input: Scenario): ScenarioOutput => ({
43	  results: input.steps.map(quoteStep),
44	});
